// Normalize the FreePBX (or any PBX) call-end webhook payload.
const raw = $input.first().json;
let body = raw.body || raw;

// Recover from broken senders that produce { "<one-big-string>": "" } shape:
//   - clients that URL-encode JSON but advertise Content-Type: application/json
//   - clients that replace ASCII spaces with literal underscores
//   - any other mangling that prevents express.json from parsing
// Try a series of recovery strategies; first one that yields valid JSON wins.
if (body && typeof body === 'object' && !Array.isArray(body)) {
  const keys = Object.keys(body);
  if (keys.length === 1 && body[keys[0]] === '' && /^\s*\{[\s\S]*\}\s*$/.test(keys[0])) {
    const raw = keys[0];
    // Strategy 1: parse as-is
    let recovered = null;
    try { recovered = JSON.parse(raw); } catch (_e) {}
    // Strategy 2: replace structural underscores with spaces (outside strings).
    if (!recovered) {
      let out = '';
      let inString = false;
      let escaped = false;
      for (let i = 0; i < raw.length; i++) {
        const c = raw[i];
        if (escaped) { out += c; escaped = false; continue; }
        if (c === '\\') { out += c; escaped = true; continue; }
        if (c === '"') { inString = !inString; out += c; continue; }
        if (!inString && c === '_') { out += ' '; continue; }
        out += c;
      }
      try { recovered = JSON.parse(out); } catch (_e) {}
    }
    if (recovered && typeof recovered === 'object') body = recovered;
  }
}

// --- direction --- (inbound / outbound; anything else -> inbound)
const directionRaw = (body.direction || 'inbound').toString().toLowerCase().trim();
const hsDirection = directionRaw === 'outbound' ? 'OUTBOUND' : 'INBOUND';

// --- src / dst / external party phone ---
const src = (body.src || body.from || body.caller || '').toString().trim();
const dst = (body.dst || body.to || body.callee || '').toString().trim();
const phoneOverride = (body.phone || '').toString().trim();
const externalRaw = phoneOverride || (hsDirection === 'OUTBOUND' ? dst : src) || src || dst || '';

const digits = externalRaw.replace(/\D/g, '');
const last10 = digits.slice(-10);
const e164 = digits ? '+' + digits : '';

// --- duration ---
const durationSec = Math.max(0, parseInt(body.duration || body.billsec || 0, 10) || 0);
const durationMs = durationSec * 1000;

// --- disposition -> hs_call_status ---
const disposition = (body.disposition || 'UNKNOWN').toString().toUpperCase().trim();
const statusMap = {
  'ANSWERED': 'COMPLETED',
  'COMPLETED': 'COMPLETED',
  'NO ANSWER': 'NO_ANSWER',
  'NOANSWER': 'NO_ANSWER',
  'NO_ANSWER': 'NO_ANSWER',
  'BUSY': 'BUSY',
  'FAILED': 'FAILED',
  'CONGESTION': 'FAILED',
  'CHANUNAVAIL': 'FAILED',
  'CANCEL': 'CANCELED',
  'CANCELED': 'CANCELED',
  'CANCELLED': 'CANCELED',
  'VOICEMAIL': 'COMPLETED',
  'UNKNOWN': 'COMPLETED'
};
const hsStatus = statusMap[disposition] || 'COMPLETED';

// --- timestamp -> epoch ms (HubSpot accepts ms or ISO) ---
function toMs(v) {
  if (v === undefined || v === null || v === '') return Date.now();
  if (typeof v === 'number') return v < 1e12 ? v * 1000 : v;
  const s = v.toString().trim();
  if (/^\d+$/.test(s)) {
    const n = parseInt(s, 10);
    return n < 1e12 ? n * 1000 : n;
  }
  // ISO or naive 'YYYY-MM-DD HH:MM:SS' (assume UTC)
  const cleaned = s.replace(' ', 'T');
  const withZ = /[Zz]|[+\-]\d{2}:?\d{2}$/.test(cleaned) ? cleaned : cleaned + 'Z';
  const d = new Date(withZ);
  return isNaN(d.getTime()) ? Date.now() : d.getTime();
}
const startMs = toMs(body.start_time || body.timestamp || body.start);
const startISO = new Date(startMs).toISOString();

// --- uniqueid (fallback if PBX did not send one) ---
const uniqueid = (body.uniqueid || body.call_id || body.callid || `${startMs}-${digits || 'na'}`).toString();

// --- caller name / contact attributes (for auto-create) ---
const callerName = (body.caller_name || body.callerid_name || body.cnam || '').toString().trim();
const firstName = (body.firstname || (callerName.split(' ')[0] || 'Unknown')).toString().slice(0, 60);
const lastNameDefault = `Caller-${last10.slice(-4) || (digits.slice(-4) || 'NA')}`;
const lastName = (body.lastname || (callerName.split(' ').slice(1).join(' ') || lastNameDefault)).toString().slice(0, 60);
const email = (body.email || '').toString().trim();

// --- presentational ---
const title = `${hsDirection === 'INBOUND' ? 'Inbound' : 'Outbound'} call ${hsDirection === 'INBOUND' ? 'from' : 'to'} ${e164 || externalRaw || 'unknown'}`;
const callBodyLines = [
  `Disposition: ${disposition} (${hsStatus})`,
  `Duration: ${durationSec}s`,
  `From: ${src || 'unknown'}`,
  `To: ${dst || 'unknown'}`,
  `Direction: ${hsDirection}`,
  `External ID: ${uniqueid}`,
  '',
  '(transcript pending)'
];
const callBody = callBodyLines.join('\n');

return [{
  json: {
    uniqueid,
    src,
    dst,
    externalRaw,
    digits,
    last10,
    e164,
    direction: directionRaw,
    hsDirection,
    durationSec,
    durationMs,
    disposition,
    hsStatus,
    startMs,
    startISO,
    firstName,
    lastName,
    email,
    title,
    callBody,
    original: body
  }
}];

// Plan node: aggregates results from upstream lookups and decides actions.
const contactSearch = $input.first().json;
const callSearch = $('Search Call by external_id').item.json;
const norm = $('Normalize').item.json;

const contactId = (contactSearch && contactSearch.results && contactSearch.results[0] && contactSearch.results[0].id) || '';
const existingCallId = (callSearch && callSearch.results && callSearch.results[0] && callSearch.results[0].id) || '';

const needCreateContact = !contactId && !!norm.digits;  // only create if we actually have a phone

return [{
  json: {
    ...norm,
    contact_id: contactId,
    existing_call_id: existingCallId,
    need_create_contact: needCreateContact
  }
}];

// Resolved-after-create: take new contact id from HubSpot response, carry forward Plan fields.
const created = $input.first().json;
const plan = $('Plan').item.json;
return [{
  json: {
    ...plan,
    contact_id: created.id || plan.contact_id,
    contact_was_created: true
  }
}];

// Resolved-existing: pass through Plan fields (contact already existed).
const plan = $input.first().json;
return [{
  json: {
    ...plan,
    contact_was_created: false
  }
}];

// Parse the GVoIPC SIMPLECDRS response (array of records) for our uniqueid.
const input = $input.first().json;
const uid = $('Normalize').item.json.uniqueid;

let records = [];
if (Array.isArray(input)) records = input;
else if (input && Array.isArray(input.data)) records = input.data;
else if (input && typeof input === 'object' && input.sc_uniqueid) records = [input];

const rec = records.find(r => (r.sc_uniqueid || '').toString() === uid) || records[0] || {};

const durationSec = parseInt(rec.sc_duration || rec.duration || rec.billsec || 0, 10) || 0;
const dispositionRaw = (rec.sc_disposition || rec.disposition || '').toString().toUpperCase().trim();
const statusMap = {
  'ANSWERED': 'COMPLETED',
  'NO ANSWER': 'NO_ANSWER',
  'BUSY': 'BUSY',
  'FAILED': 'FAILED',
  'CONGESTION': 'FAILED',
  'CHANUNAVAIL': 'FAILED',
  'CANCEL': 'CANCELED'
};
const hsStatus = statusMap[dispositionRaw] || (dispositionRaw ? 'COMPLETED' : 'COMPLETED');
const startStr = (rec.sc_start || rec.start || '').toString();
let startMs;
if (startStr) {
  const cleaned = startStr.replace(' ', 'T');
  const withZ = /[Zz]|[+\-]\d{2}:?\d{2}$/.test(cleaned) ? cleaned : cleaned + 'Z';
  const d = new Date(withZ);
  startMs = isNaN(d.getTime()) ? Date.now() : d.getTime();
} else {
  startMs = $('Normalize').item.json.startMs;
}
const startISO = new Date(startMs).toISOString();

const src = (rec.sc_calleridnum || rec.calleridnum || $('Normalize').item.json.src || '').toString();
const dst = (rec.sc_dialednum || rec.dialednum || $('Normalize').item.json.dst || '').toString();
const whoanswered = (rec.sc_whoanswered || '').toString();
const calleridname = (rec.sc_calleridname || '').toString().trim();

const hubspotCallId = $('Create Call').item.json.id;

// --- contact-name update plan ---
// Overwrite the contact's firstname/lastname when:
//   (a) we just auto-created it in this workflow run, OR
//   (b) the existing contact still has our placeholder pattern (firstname='Unknown'
//       and lastname starts with 'Caller-') — i.e., a leftover from a prior auto-create.
// Never overwrite when the existing name is something else (manual entry).
let planNeedCreate = false;
try { planNeedCreate = $('Plan').item.json.need_create_contact === true; } catch (_e) {}
let contactId = '';
try { contactId = $('Call exists?').item.json.contact_id || ''; } catch (_e) {}

let existingPlaceholder = false;
try {
  const props = (($('Search Contact').item.json.results || [])[0] || {}).properties || {};
  const fn = (props.firstname || '').trim();
  const ln = (props.lastname || '').trim();
  existingPlaceholder = fn === 'Unknown' && /^Caller-/.test(ln);
} catch (_e) {}

const nameLooksNumeric = /^[\d\s+()\-.]+$/.test(calleridname);
const shouldUpdateContact = !!contactId && !!calleridname && !nameLooksNumeric && (planNeedCreate || existingPlaceholder);
let cnFirstName = '';
let cnLastName = '';
if (shouldUpdateContact) {
  const parts = calleridname.split(/\s+/).filter(Boolean);
  if (parts.length === 1) {
    cnFirstName = parts[0].slice(0, 60);
    cnLastName = '';
  } else {
    cnFirstName = parts[0].slice(0, 60);
    cnLastName = parts.slice(1).join(' ').slice(0, 60);
  }
}

const statusLine = dispositionRaw ? `${dispositionRaw} (${hsStatus})` : 'No CDR record found';
const body = [
  `Disposition: ${statusLine}`,
  `Duration: ${durationSec}s`,
  `From: ${src || 'unknown'}` + (calleridname ? ` (${calleridname})` : ''),
  `To: ${dst || 'unknown'}`,
  whoanswered ? `Answered by: ${whoanswered}` : null,
  `External ID: ${uid}`,
  '',
  '(transcript pending)'
].filter(Boolean).join('\n');

return [{
  json: {
    hubspotCallId,
    uniqueid: uid,
    durationSec,
    durationMs: durationSec * 1000,
    dispositionRaw,
    hsStatus,
    startISO,
    src,
    dst,
    calleridname,
    body,
    found: !!records.length,
    contactId,
    shouldUpdateContact,
    cnFirstName,
    cnLastName,
    raw: rec
  }
}];

// Compose the final HubSpot call body: keep CDR header, append Summary + Transcript.
const dg = $input.first().json;
const cdr = $('Parse CDR').item.json;
const alt = (dg && dg.results && dg.results.channels && dg.results.channels[0] && dg.results.channels[0].alternatives && dg.results.channels[0].alternatives[0]) || {};
const transcript = alt.transcript || '';
const summary = (dg && dg.results && dg.results.summary && (dg.results.summary.short || dg.results.summary.summary)) || '';
const utterances = (dg && dg.results && dg.results.utterances) || [];
const durationS = (dg && dg.metadata && dg.metadata.duration) || 0;

let body = '';
body += cdr.body.replace(/\(transcript pending\)\s*$/, '').trim() + '\n\n';
if (summary) body += '## Summary\n' + summary + '\n\n';
body += '## Transcript' + (durationS ? ` (${durationS.toFixed(1)}s)` : '') + '\n';
if (utterances.length) {
  for (const u of utterances) {
    const t = (u.start || 0).toFixed(1);
    const speaker = (u.speaker !== undefined) ? `Speaker ${u.speaker}: ` : '';
    body += '[' + t + 's] ' + speaker + u.transcript + '\n';
  }
} else if (transcript) {
  body += transcript;
} else {
  body += '(no transcript - audio may have been silent)';
}
if (body.length > 65000) body = body.slice(0, 65000) + '\n…(truncated)';

return [{ json: { hubspotCallId: cdr.hubspotCallId, body, summary, transcript, durationS } }];

// Compose error email subject + body. Source for runtime metadata
// (uniqueid, hubspot call id, prev-node name) tries multiple paths for resilience.
const err = $input.first().json;
let uniqueid = '';
try { uniqueid = $('Normalize').item.json.uniqueid || ''; } catch (_) {}
let hubspotCallId = '';
try { hubspotCallId = $('Create Call').item.json.id || ''; } catch (_) {}

function firstString(...vals) { for (const v of vals) { if (typeof v === 'string' && v) return v; } return ''; }

const nodeName = firstString(
  err?.node?.name,
  err?.error?.node?.name,
  $execution?.lastNode || '',
  // n8n v2.x exposes previousNode on input metadata
  ($input.first()?.source?.[0]?.previousNode) || ''
) || 'unknown';

const httpCode = firstString(err?.httpCode, err?.error?.httpCode, err?.context?.statusCode);
const description = firstString(
  err?.description,
  err?.message,
  err?.error?.description,
  err?.error?.message
) || JSON.stringify(err).slice(0, 800);

const subject = `[n8n freepbx-hubspot-logger] error in ${nodeName} for uniqueid=${uniqueid || 'na'}`;
const text = [
  `Workflow:    FreePBX → HubSpot Call Logger v3`,
  `Node:        ${nodeName}`,
  `HTTP code:   ${httpCode || '-'}`,
  `Uniqueid:    ${uniqueid || '-'}`,
  `HubSpot id:  ${hubspotCallId || '-'}`,
  `Time:        ${new Date().toISOString()}`,
  ``,
  `--- error ---`,
  description,
].join('\n');
return [{ json: { subject, text, uniqueid, hubspotCallId, nodeName, httpCode } }];
